/* GWIT site utilities */
(function () {
  function getRoot() {
    try {
      var script = [].slice.call(document.scripts).find(function (item) {
        return (item.src || "").indexOf("assets/js/main.min.js") !== -1;
      });
      if (!script || !script.src) {
        return "";
      }
      return script.src.replace(/assets\/js\/main\.min\.js.*$/, "");
    } catch (error) {
      return "";
    }
  }

  var ROOT = getRoot();

  function absoluteUrl(path) {
    try {
      return new URL(path, ROOT || window.location.href).href;
    } catch (error) {
      return path;
    }
  }

  function injectManifest() {
    if (document.querySelector('link[rel="manifest"]')) {
      return;
    }

    try {
      var manifest = document.createElement("link");
      manifest.rel = "manifest";
      manifest.href = absoluteUrl("assets/manifest.webmanifest");
      document.head.appendChild(manifest);
    } catch (error) {}
  }

  function registerServiceWorker() {
    if (!("serviceWorker" in navigator)) {
      return;
    }

    window.addEventListener("load", function () {
      try {
        navigator.serviceWorker.register(absoluteUrl("sw.js")).catch(function () {});
      } catch (error) {}
    });
  }

  function improveImages() {
    document.querySelectorAll("img:not([loading])").forEach(function (image) {
      image.loading = "lazy";
    });

    document.querySelectorAll("img:not([alt])").forEach(function (image) {
      image.alt = "Illustration GWIT";
    });
  }

  function addOrganizationJSONLD() {
    if (document.querySelector('script[data-schema="organization"]')) {
      return;
    }

    var pathname = window.location.pathname || "/";
    var isHome =
      pathname === "/" ||
      /\/index(?:-2)?\.html?$/.test(pathname) ||
      document.body.classList.contains("home-page");

    if (!isHome) {
      return;
    }

    var script = document.createElement("script");
    script.type = "application/ld+json";
    script.dataset.schema = "organization";
    script.textContent = JSON.stringify({
      "@context": "https://schema.org",
      "@type": "Organization",
      name: "GWIT",
      legalName: "Global Wireless Integrated Technologies",
      url: absoluteUrl("index.html"),
      logo: absoluteUrl("assets/images/logos/gwit-cadre-2.png"),
      slogan: "Time to act. Time to do better.",
      email: "contact@gwit.ci",
      telephone: "+2250700077373",
      address: {
        "@type": "PostalAddress",
        streetAddress: "Cocody Angre - Djorogobite",
        postOfficeBoxNumber: "06 BP 1394 Abidjan 06",
        addressLocality: "Abidjan",
        addressCountry: "CI"
      },
      contactPoint: [
        {
          "@type": "ContactPoint",
          contactType: "sales",
          telephone: "+2250700077373",
          email: "contact@gwit.ci",
          areaServed: "Africa"
        }
      ]
    });
    document.head.appendChild(script);
  }

  function addSkipLink() {
    if (document.querySelector(".skip-link")) {
      return;
    }

    var link = document.createElement("a");
    link.href = "#main";
    link.className = "skip-link";
    link.textContent = "Aller au contenu";
    document.body.prepend(link);
  }

  function trackContacts() {
    function track(eventName, payload) {
      try {
        window.dataLayer = window.dataLayer || [];
        window.dataLayer.push({ event: eventName, payload: payload || {} });
      } catch (error) {}
    }

    document.querySelectorAll('a[href^="tel:"]').forEach(function (link) {
      link.addEventListener("click", function () {
        track("call_click", { href: link.href });
      });
    });

    document.querySelectorAll('a[href^="mailto:"]').forEach(function (link) {
      link.addEventListener("click", function () {
        track("email_click", { href: link.href });
      });
    });
  }

  function adjustHeroCTALabel() {
    try {
      var primary = document.querySelector(".hero-premium .cta-row .btn.btn-brand");
      var width = window.innerWidth || document.documentElement.clientWidth;
      if (!primary) {
        return;
      }

      if (width <= 576) {
        var text = (primary.textContent || "").trim();
        if (!primary.dataset.fullLabel) {
          primary.dataset.fullLabel = text;
        }
        if (text.length > 20) {
          primary.textContent = "Voir l'offre";
        }
        return;
      }

      if (primary.dataset.fullLabel) {
        primary.textContent = primary.dataset.fullLabel;
        delete primary.dataset.fullLabel;
      }
    } catch (error) {}
  }

  function init() {
    injectManifest();
    registerServiceWorker();
    improveImages();
    addOrganizationJSONLD();
    addSkipLink();
    trackContacts();
    adjustHeroCTALabel();
    window.addEventListener("resize", adjustHeroCTALabel);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", init);
  } else {
    init();
  }
})();
